import { bar_position, bar_styles } from '../bar/bar-encode';
import { boxplot_median_position, boxplot_median_styles } from './boxplot-median-encode';
import { boxplot_whisker_position, boxplot_whisker_styles } from './boxplot-whisker-encode';
import { bullet_levelmarker_position, bullet_levelmarker_styles } from '../bullet/bullet-levelmarker-encode';

export function boxplot_encode_collectors() {
    bar_position.call(this);
    bullet_levelmarker_position.call(this);
    boxplot_whisker_position.call(this);
    boxplot_median_position.call(this);

    bar_styles.call(this);
    bullet_levelmarker_styles.call(this);
    boxplot_whisker_styles.call(this);
    boxplot_median_styles.call(this);
}
